diff --git a/llvm/lib/Transforms/InstCombine/InstCombineNegator.cpp b/llvm/lib/Transforms/InstCombine/InstCombineNegator.cpp
index 9bd848552615..d475017e2299 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineNegator.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineNegator.cpp
@@ -29,6 +29,15 @@
 #include "llvm/IR/Instruction.h"
 #include "llvm/IR/Instructions.h"
 #include "llvm/IR/PatternMatch.h"
+static bool isPotentiallyPoisonousNSWNeg(Value *V) {
+  using namespace llvm::PatternMatch;
+  Value *X;
+  if (match(V, m_Sub(m_Zero(), m_Value(X)))) {
+    if (auto *BO = dyn_cast<BinaryOperator>(V))
+      return BO->hasNoSignedWrap();
+  }
+  return False;
+}
 #include "llvm/IR/Type.h"
 #include "llvm/IR/Use.h"
 #include "llvm/IR/User.h"
@@ -315,6 +324,20 @@ std::array<Value *, 2> Negator::getSortedOperandsOfBinOp(Instruction *I) {
       if (!(std::get<1>(I) =
                 negate(std::get<0>(I), IsNSW, Depth + 1))) // Early return.
         return nullptr;
+    using namespace llvm::PatternMatch;
+    auto *SI = cast<SelectInst>(I);
+    Value *T = SI->getTrueValue();
+    Value *F = SI->getFalseValue();
+    auto isPoisonNSWNeg = [&](Value *V) -> bool {
+      Value *X;
+      if (match(V, m_Sub(m_Zero(), m_Value(X)))) {
+        if (auto *BO = dyn_cast<BinaryOperator>(V))
+          return BO->hasNoSignedWrap();
+      }
+      return false;
+    };
+    if (isPoisonNSWNeg(T) || isPoisonNSWNeg(F))
+      return nullptr;
     }
     // All incoming values are indeed negatible. Create negated PHI node.
     PHINode *NegatedPHI = Builder.CreatePHI(
